import{_ as a,o as e,c as s,a2 as r}from"./chunks/framework.N6Nd-M9-.js";const g=JSON.parse('{"title":"📈 公司为什么从外出作业开始——个人成长（上）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（上）.md","filePath":"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（上）.md"}'),d={name:"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（上）.md"};function i(l,t,o,p,n,c){return e(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="📈-公司为什么从外出作业开始——个人成长-上" tabindex="-1">📈 公司为什么从外出作业开始——个人成长（上） <a class="header-anchor" href="#📈-公司为什么从外出作业开始——个人成长-上" aria-label="Permalink to &quot;📈 公司为什么从外出作业开始——个人成长（上）&quot;">​</a></h1><hr><h2 id="🎯-一、核心答案-这是一种考验与筛选" tabindex="-1">🎯 一、核心答案：这是一种考验与筛选 <a class="header-anchor" href="#🎯-一、核心答案-这是一种考验与筛选" aria-label="Permalink to &quot;🎯 一、核心答案：这是一种考验与筛选&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">🎯 公司的选人第一标准</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">不看重学历、经验、背景或能力。首要且唯一的问题是：<strong class="tc-blue">&quot;能不能接受跑外勤？&quot;</strong></p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">⚖️ 筛选逻辑</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">能坚定接受外勤工作，本身就证明了一种&quot;优秀的点&quot;或&quot;能力&quot;——<strong class="tc-blue">愿意从最基础、最辛苦的业务做起</strong>。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">💼 现实基础</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">很多人选择这份工作，是因为在当前条件下，这是能获得相应报酬的<strong class="tc-blue">&quot;最优解&quot;或&quot;唯一选择&quot;</strong>。既然为了赚钱，就需要接受相应的工作内容。</p></div></div></div><h2 id="🔍-二、深层原因-外勤是一场-炼心-的修行" tabindex="-1">🔍 二、深层原因：外勤是一场&quot;炼心&quot;的修行 <a class="header-anchor" href="#🔍-二、深层原因-外勤是一场-炼心-的修行" aria-label="Permalink to &quot;🔍 二、深层原因：外勤是一场&quot;炼心&quot;的修行&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:15px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-body" style="font-size:15px;margin:0;line-height:1.7;">💡 外勤工作的本质，是<strong class="tc-blue">对人&quot;心性&quot;的修炼和考验</strong>，目的是锻造能克服人性劣根性的人。</p></div></div><h3 id="需要克服的五大人性劣根性" tabindex="-1">需要克服的五大人性劣根性 <a class="header-anchor" href="#需要克服的五大人性劣根性" aria-label="Permalink to &quot;需要克服的五大人性劣根性&quot;">​</a></h3><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:15px;margin:20px 0;"><div class="tc-body" style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:12px;"><p class="tc-red tc-bold" style="font-size:22px;margin:0 0 10px 0;">😈 贪</p><p class="tc-sm" style="margin:0 0 8px 0;">欲望过重，唯利是图</p><p class="tc-xs" style="margin:0;line-height:1.5;">❌ 为短期利益欺骗客户<br>✅ 规范作业，拿得稳长久</p></div><div class="tc-body" style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:15px;border-radius:12px;"><p class="tc-green tc-bold" style="font-size:22px;margin:0 0 10px 0;">😴 惰</p><p class="tc-sm" style="margin:0 0 8px 0;">懒惰，不努力不思考</p><p class="tc-xs" style="margin:0;line-height:1.5;">❌ 敷衍话术、不愿请教<br>✅ 主动思考，承担责任</p></div><div class="tc-body" style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:15px;border-radius:12px;"><p class="tc-orange tc-bold" style="font-size:22px;margin:0 0 10px 0;">😤 嗔</p><p class="tc-sm" style="margin:0 0 8px 0;">易怒、抱怨、情绪不稳</p><p class="tc-xs" style="margin:0;line-height:1.5;">❌ 因小事动怒、顶撞管理<br>✅ 控制情绪，理性处事</p></div><div class="tc-body" style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:12px;"><p class="tc-blue tc-bold" style="font-size:22px;margin:0 0 10px 0;">🎮 玩</p><p class="tc-sm" style="margin:0 0 8px 0;">贪玩，心不定</p><p class="tc-xs" style="margin:0;line-height:1.5;">❌ 收不了心、沉迷玩乐<br>✅ 克制玩心，专注工作</p></div><div class="tc-body" style="background:rgba(236,72,153,0.06);border:1px solid rgba(236,72,153,0.15);padding:15px;border-radius:12px;"><p class="tc-pink tc-bold" style="font-size:22px;margin:0 0 10px 0;">🤪 痴</p><p class="tc-sm" style="margin:0 0 8px 0;">不明事理，缺乏认知</p><p class="tc-xs" style="margin:0;line-height:1.5;">❌ 无法沟通、不讲道理<br>✅ 提升认知，学会应对</p></div></div><h2 id="_3️⃣-三、-对员工的现实提醒-认清自己与当下" tabindex="-1">3️⃣ 三、 对员工的现实提醒：认清自己与当下 <a class="header-anchor" href="#_3️⃣-三、-对员工的现实提醒-认清自己与当下" aria-label="Permalink to &quot;3️⃣ 三、 对员工的现实提醒：认清自己与当下&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 10px 0;">🏊 频繁&quot;换泳池&quot;解决不了根本问题</p><p class="tc-body" style="font-size:14px;margin:0 0 8px 0;line-height:1.6;">就像不会游泳的人，换再多泳池还是不会。如果自身能力、心性不过关，换任何工作都难有起色。</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">真正的成长，是在一个地方<strong class="tc-blue">&quot;学会游泳&quot;</strong>，即沉下心来克服困难，提升自己。</p></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 10px 0;">💪&quot;难&quot;是正常的，也是价值的体现</p><p class="tc-body" style="font-size:14px;margin:0 0 8px 0;line-height:1.6;">有价值的事情都难。难，往往不是因为工作本身，而是因为<strong class="tc-blue">&quot;当下对工作的理解和态度&quot;</strong>——即不懂、不会、不敢开始。</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">所谓的&quot;没经验&quot;、&quot;不适合&quot;、&quot;嘴笨&quot;，往往是<strong class="tc-blue">&quot;不敢尝试&quot;、&quot;懒惰&quot;、&quot;放不下面子&quot;、&quot;不想动脑&quot;</strong>的借口。</p></div></div></div><h2 id="📝-四、总结" tabindex="-1">📝 四、总结 <a class="header-anchor" href="#📝-四、总结" aria-label="Permalink to &quot;📝 四、总结&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 12px 0;">公司通过艰苦的外勤工作，作为炼金石和培养皿。目的是：</p><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 6px 0;">🔍 筛选</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.5;">出那些心性坚定、能吃苦、愿意从基层做起的人。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 6px 0;">🔨 锻造</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.5;">员工克服人性弱点（贪、惰、嗔、玩、痴），培养抗压、自律、着眼长远的稳健心态。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:200px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 6px 0;">🤝 践行&quot;以人为本&quot;</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.5;">公司看重对人的培养。目标是训练出能担当重任的&quot;将才&quot;，而&quot;一将功成万骨枯，千金易得一将难求&quot;，严格的考验是必要的。</p></div></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><p class="tc-body tc-bold" style="margin:0;line-height:1.6;">🎯 最终导向：这不是一份轻松的工作，而是一场持续的&quot;心性&quot;修炼。能通过考验并坚持下来的人，获得的不仅是收入，更是内在的成长与蜕变。</p></div></div>',12)])])}const x=a(d,[["render",i]]);export{g as __pageData,x as default};
